import { useState } from "react";

const products = [
  {
    id: 1,
    name: "Bodyweight Burner",
    duration: "4 Weeks",
    frequency: "2x / Week",
    price: 29,
    description: "A 10–20 min add-on for the end of any session. No equipment needed — just focused bodyweight work that builds real functional strength on top of what you're already doing.",
    badge: null,
    sessions: 8,
  },
  {
    id: 2,
    name: "Abs",
    duration: "6 Weeks",
    frequency: "4x / Week",
    price: 49,
    description: "A standalone 10–20 minute workout you can run any time — on top of your current program. Progressive core work that goes far beyond basic movements to build real, lasting strength.",
    badge: "Popular",
    sessions: 24,
  },
  {
    id: 3,
    name: "Arm Blast",
    duration: "4 Weeks",
    frequency: "3x / Week",
    price: 39,
    description: "A focused add-on for your upper body. 10–20 minutes at the end of your session targeting arms and shoulders with intention — minimal equipment, maximum focus.",
    badge: null,
    sessions: 12,
  },
  {
    id: 4,
    name: "Strength For Runners",
    duration: "8 Weeks",
    frequency: "2x / Week",
    price: 99,
    description: "A dedicated 10–20 minute strength session built exclusively for runners — added on top of your existing training. Keeps your body durable, balanced, and performing at its best.",
    upsell: { text: "Add a 3rd weekly session focused on explosive power — box jumps, bounding, reactive training — for stronger, faster legs.", price: 109 },
    badge: "Best Value",
    sessions: 16,
  },
  {
    id: 5,
    name: "Stretching",
    duration: "8 Weeks",
    frequency: "5x / Week",
    price: 59,
    description: "10–20 minutes to start your morning or wind down your evening. A daily stretching practice that keeps your body loose, recovered, and ready — completely on its own or after any session.",
    badge: null,
    sessions: 40,
  },
];

export default function Store() {
  const [cart, setCart] = useState([]);
  const [cartOpen, setCartOpen] = useState(false);
  const [addedId, setAddedId] = useState(null);
  const [hoveredId, setHoveredId] = useState(null);
  const [selectedVariants, setSelectedVariants] = useState({});

  const cartCount = cart.reduce((s, i) => s + i.qty, 0);
  const cartTotal = cart.reduce((s, i) => s + i.price * i.qty, 0);

  function addToCart(product) {
    const variant = selectedVariants[product.id];
    const price = (product.upsell && variant === "upsell") ? product.upsell.price : product.price;
    const label = (product.upsell && variant === "upsell") ? "3x / Week" : product.frequency;
    const cartItem = { ...product, price, variantLabel: label };
    setCart((prev) => {
      const existing = prev.find((i) => i.id === product.id);
      if (existing) return prev.map((i) => i.id === product.id ? { ...cartItem, qty: i.qty + 1 } : i);
      return [...prev, { ...cartItem, qty: 1 }];
    });
    setAddedId(product.id);
    setTimeout(() => setAddedId(null), 900);
  }

  function removeFromCart(id) {
    setCart((prev) => prev.filter((i) => i.id !== id));
  }

  return (
    <div style={{ fontFamily: "'Barlow', sans-serif", background: "#ffffff", minHeight: "100vh", color: "#e8e8e8" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Barlow:wght@300;400;500;600;700&family=Barlow+Condensed:wght@500;600;700;800&display=swap');
        * { box-sizing: border-box; margin: 0; padding: 0; }

        body { background: #ffffff; }

        .card {
          background: #f8f8f8;
          border: 1px solid #222;
          border-radius: 0;
          overflow: hidden;
          transition: border-color 0.25s ease, transform 0.25s ease;
          display: flex;
          flex-direction: column;
          position: relative;
        }
        .card::before {
          content: '';
          position: absolute;
          top: 0; left: 0; right: 0;
          height: 2px;
          background: #7a9e7e;
          transform: scaleX(0);
          transform-origin: left;
          transition: transform 0.3s ease;
        }
        .card:hover { border-color: #333; transform: translateY(-3px); }
        .card:hover::before { transform: scaleX(1); }

        .add-btn {
          width: 100%;
          padding: 16px;
          background: #7a9e7e;
          color: #fff;
          border: none;
          font-family: 'Barlow Condensed', sans-serif;
          font-size: 13px;
          font-weight: 700;
          letter-spacing: 3px;
          text-transform: uppercase;
          cursor: pointer;
          transition: background 0.2s ease;
          margin-top: auto;
        }
        .add-btn:hover { background: #5f856a; }
        .add-btn.added { background: #5f856a; }

        .cart-drawer {
          position: fixed; top: 0; right: 0; height: 100vh;
          width: 380px; background: #ffffff;
          border-left: 1px solid #222;
          transform: translateX(100%);
          transition: transform 0.4s cubic-bezier(.25,.8,.25,1);
          z-index: 200;
          display: flex; flex-direction: column;
        }
        .cart-drawer.open { transform: translateX(0); }

        .overlay {
          position: fixed; inset: 0; background: rgba(0,0,0,0.7);
          z-index: 150; opacity: 0; pointer-events: none;
          transition: opacity 0.3s;
        }
        .overlay.show { opacity: 1; pointer-events: all; }

        .grid {
          display: grid;
          grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
          gap: 1px;
          background: #1a1a1a;
          border: 1px solid #1a1a1a;
        }

        .badge {
          display: inline-block;
          background: transparent;
          color: #7a9e7e;
          font-family: 'Barlow Condensed', sans-serif;
          font-size: 10px;
          font-weight: 700;
          letter-spacing: 3px;
          text-transform: uppercase;
          padding: 3px 0;
          margin-bottom: 10px;
          border-left: 2px solid #7a9e7e;
          padding-left: 8px;
        }

        .stat-item {
          display: flex;
          flex-direction: column;
          gap: 2px;
        }
        .stat-label {
          font-size: 9px;
          letter-spacing: 2px;
          text-transform: uppercase;
          color: #444;
          font-weight: 600;
        }
        .stat-value {
          font-size: 13px;
          font-weight: 600;
          color: #aaa;
          font-family: 'Barlow Condensed', sans-serif;
          letter-spacing: 0.5px;
        }

        .divider {
          width: 1px;
          background: #222;
          align-self: stretch;
        }

        .cart-item-divider {
          border: none;
          border-top: 1px solid #1e1e1e;
          margin: 0;
        }

        .checkout-btn {
          width: 100%;
          padding: 16px;
          background: #7a9e7e;
          color: #fff;
          border: none;
          font-family: 'Barlow Condensed', sans-serif;
          font-size: 13px;
          font-weight: 700;
          letter-spacing: 3px;
          text-transform: uppercase;
          cursor: pointer;
          border-radius: 0;
          transition: background 0.2s;
        }
        .checkout-btn:hover { background: #5f856a; }

        .cart-btn {
          background: none;
          border: 1px solid #2a2a2a;
          padding: 10px 22px;
          cursor: pointer;
          font-family: 'Barlow Condensed', sans-serif;
          font-size: 12px;
          font-weight: 700;
          letter-spacing: 3px;
          text-transform: uppercase;
          color: #aaa;
          display: flex;
          align-items: center;
          gap: 10px;
          transition: border-color 0.2s, color 0.2s;
        }
        .cart-btn:hover { border-color: #7a9e7e; color: #fff; }

        .noex-tag {
          display: inline-block;
          border: 1px solid #7a9e7e;
          color: #7a9e7e;
          font-family: 'Barlow Condensed', sans-serif;
          font-size: 10px;
          font-weight: 700;
          letter-spacing: 4px;
          text-transform: uppercase;
          padding: 4px 12px;
          margin-bottom: 24px;
        }

        @keyframes fadeIn {
          from { opacity: 0; transform: translateY(10px); }
          to { opacity: 1; transform: translateY(0); }
        }
        .card { animation: fadeIn 0.4s ease both; }

        @media (max-width: 600px) {
          .cart-drawer { width: 100vw; }
          .grid { grid-template-columns: 1fr; }
        }
      `}</style>

      {/* Header */}
      <header style={{ background: "#ffffff", borderBottom: "1px solid #1a1a1a", padding: "0 40px", display: "flex", alignItems: "center", justifyContent: "space-between", height: 64, position: "sticky", top: 0, zIndex: 100 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 14 }}>
          <img src="data:image/png;base64," alt="NOEX" style={{ width: 32, height: 32, objectFit: "contain", filter: "invert(1) brightness(0.6)" }} />
          <div>
            <div style={{ fontFamily: "'Barlow Condensed', sans-serif", fontSize: 18, fontWeight: 800, color: "#fff", letterSpacing: -1, textTransform: "uppercase" }}>Jordan Rowe</div>
            <div style={{ fontSize: 9, letterSpacing: 4, color: "#444", textTransform: "uppercase", fontWeight: 600, marginTop: 1 }}>RVA's Personal Trainer</div>
          </div>
        </div>
        <button className="cart-btn" onClick={() => setCartOpen(true)}>
          Cart
          {cartCount > 0 && (
            <span style={{ background: "#7a9e7e", color: "#fff", padding: "1px 8px", fontSize: 11, fontWeight: 700, fontFamily: "'Barlow Condensed', sans-serif", letterSpacing: 1 }}>{cartCount}</span>
          )}
        </button>
      </header>

      {/* Hero */}
      <div style={{ background: "#ffffff", borderBottom: "1px solid #1a1a1a", padding: "70px 40px 60px" }}>
        <div style={{ maxWidth: 700 }}>
          <div className="noex-tag">NOEX · Exclusive Add-Ons</div>
          <h1 style={{ fontFamily: "'Barlow Condensed', sans-serif", fontWeight: 800, fontSize: "clamp(64px, 10vw, 110px)", lineHeight: 0.92, color: "#7a9e7e", textTransform: "uppercase", letterSpacing: -3, marginBottom: 28 }}>
            ADDI<br />TIONS.
          </h1>
          <div style={{ width: 40, height: 2, background: "#7a9e7e", marginBottom: 24 }} />
          <p style={{ fontSize: 14, color: "#555", lineHeight: 1.9, maxWidth: 480, fontWeight: 400, letterSpacing: 0.3 }}>
            These programs are built to stack on top of what you're already doing. Bolt them onto the end of your current workouts for that exclusive NOEX edge — more focus, more results, zero fluff.
          </p>
        </div>
      </div>

      {/* Programs */}
      <main style={{ padding: "48px 40px 80px", background: "#ffffff" }}>
        <div style={{ display: "flex", alignItems: "baseline", justifyContent: "space-between", marginBottom: 32 }}>
          <h2 style={{ fontFamily: "'Barlow Condensed', sans-serif", fontSize: 13, fontWeight: 700, textTransform: "uppercase", letterSpacing: 1, color: "#444" }}>All Additions — {products.length} Programs</h2>
          <span style={{ fontSize: 11, color: "#333", letterSpacing: 2, textTransform: "uppercase" }}>Instant Access</span>
        </div>

        <div className="grid">
          {products.map((product, i) => (
            <div
              key={product.id}
              className="card"
              style={{ animationDelay: `${i * 0.07}s` }}
              onMouseEnter={() => setHoveredId(product.id)}
              onMouseLeave={() => setHoveredId(null)}
            >
              <div style={{ padding: "28px 24px 24px" }}>
                {/* Top row */}
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 20 }}>
                  <img
                    src="data:image/png;base64,"
                    alt="NOEX"
                    style={{ width: 40, height: 40, objectFit: "contain", filter: "invert(1) brightness(0.4)", transition: "filter 0.3s", ...(hoveredId === product.id ? { filter: "invert(1) brightness(0.7)" } : {}) }}
                  />
                  {product.badge && <div className="badge">{product.badge}</div>}
                </div>

                <h3 style={{ fontFamily: "'Barlow Condensed', sans-serif", fontSize: 26, fontWeight: 800, marginBottom: 12, textTransform: "uppercase", letterSpacing: -1, color: "#111", lineHeight: 1 }}>{product.name}</h3>

                <p style={{ fontSize: 13, color: "#555", lineHeight: 1.7, marginBottom: product.upsell ? 12 : 24, fontWeight: 400 }}>{product.description}</p>

                {product.upsell && (
                  <div style={{ background: "#f0f5f1", border: "1px solid #c5d9c7", borderRadius: 6, padding: "10px 14px", marginBottom: 24, display: "flex", alignItems: "flex-start", gap: 10 }}>
                    <div style={{ flexShrink: 0, marginTop: 2 }}>
                      <div style={{ width: 18, height: 18, borderRadius: "50%", background: "#7a9e7e", display: "flex", alignItems: "center", justifyContent: "center" }}>
                        <span style={{ color: "#fff", fontSize: 11, fontWeight: 700, lineHeight: 1 }}>+</span>
                      </div>
                    </div>
                    <div>
                      <div style={{ fontFamily: "'Barlow Condensed', sans-serif", fontSize: 11, fontWeight: 700, letterSpacing: 2, textTransform: "uppercase", color: "#7a9e7e", marginBottom: 3 }}>Add-On Available</div>
                      <div style={{ fontSize: 12, color: "#555", lineHeight: 1.6 }}>{product.upsell.text}</div>
                      <div style={{ fontFamily: "'Barlow Condensed', sans-serif", fontSize: 15, fontWeight: 700, color: "#111", marginTop: 5 }}>${product.upsell.price} <span style={{ fontFamily: "'Barlow', sans-serif", fontSize: 11, color: "#888", fontWeight: 400 }}>total with add-on</span></div>
                    </div>
                  </div>
                )}

                {/* Stats row */}
                <div style={{ display: "flex", gap: 0, marginBottom: 24, borderTop: "1px solid #1e1e1e", borderBottom: "1px solid #1e1e1e", padding: "14px 0" }}>
                  <div className="stat-item" style={{ flex: 1 }}>
                    <span className="stat-label">Duration</span>
                    <span className="stat-value">{product.duration}</span>
                  </div>
                  <div className="divider" />
                  <div className="stat-item" style={{ flex: 1, paddingLeft: 16 }}>
                    <span className="stat-label">Frequency</span>
                    <span className="stat-value">{product.frequency}</span>
                  </div>
                  <div className="divider" />
                  <div className="stat-item" style={{ flex: 1, paddingLeft: 16 }}>
                    <span className="stat-label">Sessions</span>
                    <span className="stat-value">{product.sessions} Total</span>
                  </div>
                </div>

                <div style={{ fontFamily: "'Barlow Condensed', sans-serif", fontSize: 36, fontWeight: 800, color: "#111", letterSpacing: -2 }}>
                  ${product.price}
                  <span style={{ fontFamily: "'Barlow', sans-serif", fontSize: 12, color: "#444", fontWeight: 400, marginLeft: 6, letterSpacing: 1 }}>ONE-TIME</span>
                </div>
              </div>

              {product.upsell && (
                <div style={{ padding: "14px 20px", borderTop: "1px solid #1e1e1e", display: "flex", gap: 8 }}>
                  <button
                    onClick={() => setSelectedVariants(v => ({ ...v, [product.id]: "base" }))}
                    style={{ flex: 1, padding: "10px 8px", border: "1.5px solid", borderColor: (!selectedVariants[product.id] || selectedVariants[product.id] === "base") ? "#2b2e2b" : "#ddd", background: (!selectedVariants[product.id] || selectedVariants[product.id] === "base") ? "#2b2e2b" : "#fff", color: (!selectedVariants[product.id] || selectedVariants[product.id] === "base") ? "#fff" : "#888", borderRadius: 6, cursor: "pointer", fontFamily: "'Barlow Condensed', sans-serif", fontSize: 12, fontWeight: 700, letterSpacing: 1, textTransform: "uppercase", transition: "all 0.2s" }}>
                    <div>2x / Week</div>
                    <div style={{ fontSize: 14, marginTop: 2 }}>${product.price}</div>
                  </button>
                  <button
                    onClick={() => setSelectedVariants(v => ({ ...v, [product.id]: "upsell" }))}
                    style={{ flex: 1, padding: "10px 8px", border: "1.5px solid", borderColor: selectedVariants[product.id] === "upsell" ? "#7a9e7e" : "#ddd", background: selectedVariants[product.id] === "upsell" ? "#7a9e7e" : "#fff", color: selectedVariants[product.id] === "upsell" ? "#fff" : "#888", borderRadius: 6, cursor: "pointer", fontFamily: "'Barlow Condensed', sans-serif", fontSize: 12, fontWeight: 700, letterSpacing: 1, textTransform: "uppercase", transition: "all 0.2s" }}>
                    <div>3x / Week</div>
                    <div style={{ fontSize: 14, marginTop: 2 }}>${product.upsell.price}</div>
                  </button>
                </div>
              )}
              <button
                className={`add-btn ${addedId === product.id ? "added" : ""}`}
                onClick={() => addToCart(product)}
              >
                {addedId === product.id ? "✓ Added" : "Get This Program"}
              </button>
            </div>
          ))}
        </div>
      </main>

      {/* Footer bar */}
      <div style={{ borderTop: "1px solid #1a1a1a", padding: "24px 40px", display: "flex", flexWrap: "wrap", gap: 40, justifyContent: "center" }}>
        {["Instant Digital Access", "Coach-Designed", "Based in Richmond, VA", "NOEX Exclusive"].map((item) => (
          <div key={item} style={{ fontSize: 10, color: "#333", fontWeight: 600, letterSpacing: 3, textTransform: "uppercase" }}>{item}</div>
        ))}
      </div>

      {/* Overlay */}
      <div className={`overlay ${cartOpen ? "show" : ""}`} onClick={() => setCartOpen(false)} />

      {/* Cart Drawer */}
      <div className={`cart-drawer ${cartOpen ? "open" : ""}`}>
        <div style={{ padding: "24px 28px 20px", borderBottom: "1px solid #1e1e1e", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          <div style={{ fontFamily: "'Barlow Condensed', sans-serif", fontSize: 20, fontWeight: 800, textTransform: "uppercase", letterSpacing: -1, color: "#111" }}>
            Your Cart
            {cartCount > 0 && <span style={{ fontFamily: "'Barlow', sans-serif", fontSize: 13, color: "#444", fontWeight: 300, marginLeft: 8, textTransform: "none", letterSpacing: 0 }}>({cartCount})</span>}
          </div>
          <button onClick={() => setCartOpen(false)} style={{ background: "none", border: "none", cursor: "pointer", fontSize: 22, color: "#444", lineHeight: 1 }}>×</button>
        </div>

        <div style={{ flex: 1, overflowY: "auto", padding: "8px 0" }}>
          {cart.length === 0 ? (
            <div style={{ textAlign: "center", padding: "60px 28px", color: "#333" }}>
              <div style={{ fontFamily: "'Barlow Condensed', sans-serif", fontSize: 13, letterSpacing: 3, textTransform: "uppercase", fontWeight: 700 }}>Cart is empty</div>
              <div style={{ fontSize: 12, color: "#2a2a2a", marginTop: 8, letterSpacing: 1 }}>Add a program to get started</div>
            </div>
          ) : (
            cart.map((item) => (
              <div key={item.id} style={{ display: "flex", gap: 14, padding: "18px 28px", borderBottom: "1px solid #1a1a1a" }}>
                <div style={{ width: 44, height: 44, background: "#f0f0f0", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
                  <img src="data:image/png;base64," alt="NOEX" style={{ width: 28, height: 28, objectFit: "contain", filter: "invert(1) brightness(0.5)" }} />
                </div>
                <div style={{ flex: 1 }}>
                  <div style={{ fontFamily: "'Barlow Condensed', sans-serif", fontSize: 15, fontWeight: 800, textTransform: "uppercase", letterSpacing: -1, color: "#111", marginBottom: 3 }}>{item.name}</div>
                  <div style={{ fontSize: 11, color: "#444", letterSpacing: 1 }}>{item.duration} · {item.variantLabel || item.frequency}</div>
                  <div style={{ fontFamily: "'Barlow Condensed', sans-serif", fontSize: 18, fontWeight: 700, color: "#555", marginTop: 4, letterSpacing: -1 }}>${item.price}</div>
                </div>
                <button onClick={() => removeFromCart(item.id)} style={{ background: "none", border: "none", cursor: "pointer", color: "#333", fontSize: 18, alignSelf: "flex-start", transition: "color 0.2s" }}
                  onMouseEnter={e => e.target.style.color = "#fff"}
                  onMouseLeave={e => e.target.style.color = "#333"}
                >×</button>
              </div>
            ))
          )}
        </div>

        {cart.length > 0 && (
          <div style={{ padding: "20px 28px 32px", borderTop: "1px solid #1e1e1e" }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline", marginBottom: 20 }}>
              <span style={{ fontSize: 10, color: "#444", letterSpacing: 3, textTransform: "uppercase", fontWeight: 600 }}>Total</span>
              <span style={{ fontFamily: "'Barlow Condensed', sans-serif", fontSize: 32, fontWeight: 800, color: "#111", letterSpacing: -2 }}>${cartTotal}</span>
            </div>
            <button className="checkout-btn">Proceed to Checkout</button>
            <button onClick={() => setCart([])} style={{ width: "100%", marginTop: 12, padding: "12px", background: "none", color: "#333", border: "none", fontFamily: "'Barlow Condensed', sans-serif", fontSize: 11, fontWeight: 700, letterSpacing: 3, textTransform: "uppercase", cursor: "pointer", transition: "color 0.2s" }}
              onMouseEnter={e => e.target.style.color = "#fff"}
              onMouseLeave={e => e.target.style.color = "#333"}
            >
              Clear Cart
            </button>
          </div>
        )}
      </div>
    </div>
  );
}
